// SendPlanMessage is the resolver for the sendPlanMessage field.
func (r *mutationResolver) SendPlanMessage(ctx context.Context, date model.Date, message string) (*model.DayPlan, error) {
	pgDate := pgtype.Date{Time: date.Time, Valid: true}

	// Check if plan exists
	existingPlan, planErr := r.DayPlanStore.GetDayPlanByDate(ctx, pgDate)
	isNewPlan := planErr != nil
	isReplan := !isNewPlan && existingPlan.Status == "accepted"

	// Create plan if it doesn't exist
	if isNewPlan {
		created, err := r.DayPlanStore.CreateDayPlan(ctx, db.CreateDayPlanParams{
			PlanDate: pgDate,
			Status:   "draft",
			Blocks:   []byte("[]"),
		})
		if err != nil {
			return nil, fmt.Errorf("creating plan: %w", err)
		}
		existingPlan = created
	}

	// Save previous state before replanning so user can revert
	if isReplan {
		if err := r.DayPlanStore.SavePreviousState(ctx, db.SavePreviousStateParams{ID: existingPlan.ID}); err != nil {
			log.Printf("warning: failed to save previous plan state: %v", err)
		}
	}

	// Gather context data for the prompt
	input, err := r.buildPlanChatInput(ctx, existingPlan, message, date.Time, isReplan)
	if err != nil {
		return nil, fmt.Errorf("building plan input: %w", err)
	}

	// Call the planner
	output, err := r.Planner.PlanChat(ctx, input)

	// Store messages regardless of success/failure
	// Insert user message
	_, msgErr := r.DayPlanStore.CreatePlanMessage(ctx, db.CreatePlanMessageParams{
		PlanID:  existingPlan.ID,
		Role:    "user",
		Content: message,
	})
	if msgErr != nil {
		return nil, fmt.Errorf("storing user message: %w", msgErr)
	}

	// Store AI response(s)
	if output != nil {
		for _, raw := range output.RawResponses {
			r.DayPlanStore.CreatePlanMessage(ctx, db.CreatePlanMessageParams{
				PlanID:  existingPlan.ID,
				Role:    "assistant",
				Content: raw,
			})
		}
	}

	if err != nil {
		return nil, err
	}

	// Convert planner blocks to model blocks
	aiBlocks := make([]*model.PlanBlock, len(output.Blocks))
	for i, b := range output.Blocks {
		block := &model.PlanBlock{
			ID:       b.ID,
			Time:     b.Time,
			Duration: b.Duration,
			Title:    b.Title,
			Category: model.Category(strings.ToUpper(b.Category)),
			Notes:    b.Notes,
			Skipped:  b.Skipped,
		}
		if b.TaskID != nil && *b.TaskID != "" && *b.TaskID != "null" {
			if uid, uerr := uuid.Parse(*b.TaskID); uerr == nil {
				block.TaskID = &uid
			}
		}
		if b.RoutineID != nil && *b.RoutineID != "" && *b.RoutineID != "null" {
			if uid, uerr := uuid.Parse(*b.RoutineID); uerr == nil {
				block.RoutineID = &uid
			}
		}
		aiBlocks[i] = block
	}

	// For replanning, merge preserved blocks with AI's new blocks
	var modelBlocks []*model.PlanBlock
	if isReplan {
		existing := parseBlocks(existingPlan.Blocks)

		// Build sets of preserved task/routine IDs to detect duplicates
		preservedTaskIDs := make(map[string]bool)
		preservedRoutineIDs := make(map[string]bool)
		for _, b := range existing {
			if b.Done || b.Skipped {
				modelBlocks = append(modelBlocks, b)
				if b.TaskID != nil {
					preservedTaskIDs[b.TaskID.String()] = true
				}
				if b.RoutineID != nil {
					preservedRoutineIDs[b.RoutineID.String()] = true
				}
			}
		}

		// Also preserve past blocks that are neither done nor skipped (they happened but
		// the user just didn't mark them). This prevents them from being lost during replan.
		if input.CurrentTime != "" {
			for _, b := range existing {
				if !b.Done && !b.Skipped && b.Time < input.CurrentTime {
					modelBlocks = append(modelBlocks, b)
					if b.TaskID != nil {
						preservedTaskIDs[b.TaskID.String()] = true
					}
					if b.RoutineID != nil {
						preservedRoutineIDs[b.RoutineID.String()] = true
					}
				}
			}
		}

		// Filter AI blocks: remove duplicates and past-time blocks
		for _, b := range aiBlocks {
			// Drop blocks scheduled in the past
			if input.CurrentTime != "" && b.Time < input.CurrentTime {
				continue
			}
			// Drop blocks that duplicate a preserved task
			if b.TaskID != nil && preservedTaskIDs[b.TaskID.String()] {
				continue
			}
			// Drop blocks that duplicate a preserved routine
			if b.RoutineID != nil && preservedRoutineIDs[b.RoutineID.String()] {
				continue
			}
			modelBlocks = append(modelBlocks, b)
		}

		sort.Slice(modelBlocks, func(i, j int) bool {
			return modelBlocks[i].Time < modelBlocks[j].Time
		})
	} else {
		// For initial plans of today, filter out past-time blocks
		if input.CurrentTime != "" {
			var filtered []*model.PlanBlock
			for _, b := range aiBlocks {
				if b.Time >= input.CurrentTime {
					filtered = append(filtered, b)
				}
			}
			modelBlocks = filtered
		} else {
			modelBlocks = aiBlocks
		}
	}

	blocksData, err := marshalBlocks(modelBlocks)
	if err != nil {
		return nil, fmt.Errorf("marshaling blocks: %w", err)
	}

	// Update blocks
	updated, err := r.DayPlanStore.UpdateDayPlanBlocks(ctx, db.UpdateDayPlanBlocksParams{
		ID:     existingPlan.ID,
		Blocks: blocksData,
	})
	if err != nil {
		return nil, fmt.Errorf("updating blocks: %w", err)
	}

	// If replanning, set status back to draft
	if isReplan {
		updated, err = r.DayPlanStore.UpdateDayPlanStatus(ctx, db.UpdateDayPlanStatusParams{
			ID:     existingPlan.ID,
			Status: "draft",
		})
		if err != nil {
			return nil, fmt.Errorf("resetting plan status: %w", err)
		}
	}

	messages, err := r.DayPlanStore.GetPlanMessages(ctx, updated.ID)
	if err != nil {
		return nil, fmt.Errorf("fetching plan messages: %w", err)
	}
	return dayPlanConverter.FromDB(updated, messages), nil
}

// AcceptPlan is the resolver for the acceptPlan field.
func (r *mutationResolver) AcceptPlan(ctx context.Context, date model.Date) (*model.DayPlan, error) {
	pgDate := pgtype.Date{Time: date.Time, Valid: true}
	plan, err := r.DayPlanStore.GetDayPlanByDate(ctx, pgDate)
	if err != nil {
		return nil, fmt.Errorf("No plan exists for this date")
	}
	if plan.Status == "accepted" {
		messages, err := r.DayPlanStore.GetPlanMessages(ctx, plan.ID)
		if err != nil {
			return nil, fmt.Errorf("fetching plan messages: %w", err)
		}
		return dayPlanConverter.FromDB(plan, messages), nil
	}
	updated, err := r.DayPlanStore.UpdateDayPlanStatus(ctx, db.UpdateDayPlanStatusParams{
		ID:     plan.ID,
		Status: "accepted",
	})
	if err != nil {
		return nil, fmt.Errorf("accepting plan: %w", err)
	}
	messages, err := r.DayPlanStore.GetPlanMessages(ctx, updated.ID)
	if err != nil {
		return nil, fmt.Errorf("fetching plan messages: %w", err)
	}
	return dayPlanConverter.FromDB(updated, messages), nil
}

